316: func (d *AlertsRouter) Send(ctx context.Context, key models.AlertRuleKey, alerts definitions.PostableAlerts) {
317: 	logger := d.logger.New(key.LogContext()...)
318: 	if len(alerts.PostableAlerts) == 0 {
319: 		logger.Info("No alerts to notify about")
320: 		return
321: 	}
322: 	// Send alerts to local notifier if they need to be handled internally
323: 	// or if no external AMs have been discovered yet.
324: 	d.adminConfigMtx.RLock()
325: 	defer d.adminConfigMtx.RUnlock()
326: 	var localNotifierExist, externalNotifierExist bool
327: 	if d.sendAlertsTo[key.OrgID] == models.ExternalAlertmanagers && len(d.alertmanagersFor(key.OrgID)) > 0 {
328: 		logger.Debug("All alerts for the given org should be routed to external notifiers only. skipping the internal notifier.")
329: 	} else {
330: 		logger.Info("Sending alerts to local notifier", "count", len(alerts.PostableAlerts))
331: 		n, err := d.multiOrgNotifier.AlertmanagerFor(key.OrgID)
332: 		if err == nil {
333: 			localNotifierExist = true
334: 			if err := n.PutAlerts(ctx, alerts); err != nil {
335: 				logger.Error("Failed to put alerts in the local notifier", "count", len(alerts.PostableAlerts), "error", err)
336: 			}
337: 		} else {
338: 			if errors.Is(err, notifier.ErrNoAlertmanagerForOrg) {
339: 				logger.Debug("Local notifier was not found")
340: 			} else {
341: 				logger.Error("Local notifier is not available", "error", err)
342: 			}
343: 		}
344: 	}
345: 
346: 	// Send alerts to external Alertmanager(s) if we have a sender for this organization
347: 	// and alerts are not being handled just internally.
348: 	s, ok := d.externalAlertmanagers[key.OrgID]
349: 	if ok && d.sendAlertsTo[key.OrgID] != models.InternalAlertmanager {
350: 		logger.Info("Sending alerts to external notifier", "count", len(alerts.PostableAlerts))
351: 		s.SendAlerts(alerts)
352: 		externalNotifierExist = true
353: 	}
354: 
355: 	if !localNotifierExist && !externalNotifierExist {
356: 		logger.Error("No external or internal notifier - alerts not delivered", "count", len(alerts.PostableAlerts))
357: 	}
358: }
359: 
360: // AlertmanagersFor returns all the discovered Alertmanager(s) for a particular organization.
361: func (d *AlertsRouter) AlertmanagersFor(orgID int64) []*url.URL {
362: 	d.adminConfigMtx.RLock()
363: 	defer d.adminConfigMtx.RUnlock()
364: 	return d.alertmanagersFor(orgID)
365: }
366: 
367: func (d *AlertsRouter) alertmanagersFor(orgID int64) []*url.URL {
368: 	s, ok := d.externalAlertmanagers[orgID]
369: 	if !ok {
370: 		return []*url.URL{}
371: 	}
372: 	return s.Alertmanagers()
373: }
374: 
375: // DroppedAlertmanagersFor returns all the dropped Alertmanager(s) for a particular organization.
376: func (d *AlertsRouter) DroppedAlertmanagersFor(orgID int64) []*url.URL {
377: 	d.adminConfigMtx.RLock()
378: 	defer d.adminConfigMtx.RUnlock()
379: 	s, ok := d.externalAlertmanagers[orgID]
380: 	if !ok {
381: 		return []*url.URL{}
382: 	}
383: 
384: 	return s.DroppedAlertmanagers()
385: }
386: 
387: // Run starts regular updates of the configuration.
388: func (d *AlertsRouter) Run(ctx context.Context) error {
389: 	for {
390: 		select {
391: 		case <-time.After(d.adminConfigPollInterval):
392: 			if err := d.SyncAndApplyConfigFromDatabase(ctx); err != nil {
393: 				d.logger.Error("Unable to sync admin configuration", "error", err)
394: 			}
395: 		case <-ctx.Done():
396: 			// Stop sending alerts to all external Alertmanager(s).
397: 			d.adminConfigMtx.Lock()
398: 			for orgID, s := range d.externalAlertmanagers {
399: 				delete(d.externalAlertmanagers, orgID) // delete before we stop to make sure we don't accept any more alerts.
400: 				s.Stop()
401: 			}
402: 			d.adminConfigMtx.Unlock()
403: 
404: 			return nil
405: 		}
406: 	}
407: }
